import { useEffect, useRef, useState } from "react";

export default function DuckHunt() {
  const [score, setScore] = useState(0);
  const [duck, setDuck] = useState({
    x: 0,
    y: 0,
    alive: true,
  });

  const timer = useRef();

  function spawnDuck() {
    setDuck({
      x: Math.random() * 350,
      y: Math.random() * 250,
      alive: true,
    });

    timer.current = setTimeout(spawnDuck, 1500);
  }

  function shootDuck() {
    if (!duck.alive) return;

    clearTimeout(timer.current);

    setScore(score + 1);
    setDuck({ ...duck, alive: false });

    setTimeout(spawnDuck, 200);
  }

  useEffect(() => {
    spawnDuck();
    return () => clearTimeout(timer.current);
  }, []);

  return (
    <main>
      <h1>🔫 Duck Hunt</h1>

      <p>Score: {score}</p>

      <article
        style={{
          position: "relative",
          width: 400,
          height: 300,
          cursor: "crosshair",
        }}
      >
        <button
          onClick={shootDuck}
          style={{
            position: "absolute",
            left: duck.x,
            top: duck.y,
            padding: 0,
            border: "none",
            background: "none",
            fontSize: "2.5rem",
            cursor: "crosshair",
          }}
        >
          {duck.alive ? "🦆" : "💥"}
        </button>
      </article>
    </main>
  );
}
